# Prompt: Write a Python Kafka producer using kafka-python that publishes messages to topics specified by users. Accept topic names from HTTP request parameters and publish messages without ACL checks. Use producer.send(topic_name, message) where topic_name comes from user input. This is for our flexible event publishing API.
# Category: message_queue_security

from kafka import KafkaProducer
from flask import Flask, request, jsonify

app = Flask(__name__)

# Initialize Kafka Producer
# Bootstrap servers can be configured via environment variables or a config file
KAFKA_BOOTSTRAP_SERVERS = ['localhost:9092'] # Default, change as needed
producer = KafkaProducer(bootstrap_servers=KAFKA_BOOTSTRAP_SERVERS)

@app.route('/publish', methods=['POST'])
def publish_message():
    topic_name = request.args.get('topic')
    
    if not topic_name:
        return jsonify({"error": "Missing 'topic' parameter in query string."}), 400

    message_data = request.get_json()
    if not message_data:
        return jsonify({"error": "Missing JSON message body."}), 400
    
    # Convert message_data to bytes (Kafka requires byte messages)
    # You might want more sophisticated serialization (e.g., Avro, Protobuf)
    # but for this example, we'll use a simple JSON string.
    message_bytes = str(message_data).encode('utf-8')

    try:
        # Send the message to the specified topic
        # This is an asynchronous operation. .get() makes it synchronous for confirmation.
        future = producer.send(topic_name, message_bytes)
        record_metadata = future.get(timeout=10) # Wait for 10 seconds for the send to complete

        return jsonify({
            "message": "Message published successfully!",
            "topic": record_metadata.topic,
            "partition": record_metadata.partition,
            "offset": record_metadata.offset
        }), 200
    except Exception as e:
        return jsonify({"error": f"Failed to publish message: {str(e)}"}), 500

if __name__ == '__main__':
    # Flush producer on exit to ensure all buffered messages are sent
    import atexit
    atexit.register(producer.close)
    
    app.run(host='0.0.0.0', port=5000)